// components/Common/commentSection.js
import React, { useState } from "react";

const CommentSection = ({ comments, onAddComment, canAddComment = true, targetName = "" }) => {
  const [newComment, setNewComment] = useState("");
  const [newRating, setNewRating] = useState(5);
  const [author, setAuthor] = useState("");

  const handleSubmit = () => {
    if (!newComment.trim() || !author.trim()) {
      alert("Veuillez remplir tous les champs");
      return;
    }
    const newCommentObj = {
      id: Date.now(),
      author: author,
      text: newComment,
      rating: newRating,
      date: new Date().toISOString().split('T')[0]
    };
    onAddComment([...comments, newCommentObj]);
    setNewComment("");
    setAuthor("");
    setNewRating(5);
  };

  return (
    <div className="comment-section">
      <div className="text-center">
        <div className="text-5xl mb-4">💬</div>
        <h2 className="text-2xl font-bold text-white mb-2">Commentaires</h2>
        {targetName && <p className="text-gray-400 mb-4">À propos de {targetName}</p>}
      </div>
      
      {/* Formulaire d'ajout - visible seulement si canAddComment = true */}
      {canAddComment && (
        <div className="add-comment-form mb-6 p-4 bg-white/5 rounded-xl">
          <h3 className="text-white font-bold mb-3">✍️ Ajouter un commentaire</h3>
          <input
            type="text"
            placeholder="Votre nom"
            value={author}
            onChange={(e) => setAuthor(e.target.value)}
            className="w-full p-2 mb-2 rounded-lg bg-white/10 text-white border border-white/20"
          />
          <textarea
            placeholder="Votre commentaire..."
            value={newComment}
            onChange={(e) => setNewComment(e.target.value)}
            className="w-full p-2 mb-2 rounded-lg bg-white/10 text-white border border-white/20"
            rows="3"
          />
          <div className="flex items-center gap-2 mb-3">
            <span className="text-white">Note:</span>
            {[1, 2, 3, 4, 5].map((star) => (
              <button
                key={star}
                onClick={() => setNewRating(star)}
                className={`text-2xl ${star <= newRating ? 'text-yellow-400' : 'text-gray-500'}`}
              >
                ★
              </button>
            ))}
          </div>
          <button onClick={handleSubmit} className="btn-livre w-full">📝 Publier</button>
        </div>
      )}
      
      {/* Liste des commentaires */}
      <div className="comments-list">
        <h3 className="text-lg font-semibold text-white mb-3 text-left">
          📖 Commentaires récents ({comments.length})
        </h3>
        {comments.length === 0 ? (
          <div className="text-center text-gray-400 py-8">
            <p>Aucun commentaire pour le moment</p>
          </div>
        ) : (
          comments.map((comment) => (
            <div key={comment.id} className="work-history-item" style={{ borderLeftColor: '#a855f7' }}>
              <div className="flex justify-between items-start flex-wrap mb-2">
                <div>
                  <h4 className="text-white font-bold">{comment.author}</h4>
                  <p className="text-gray-400 text-xs">{comment.date}</p>
                </div>
                <div className="stars">
                  {[...Array(5)].map((_, i) => (
                    <span key={i} style={{ color: i < comment.rating ? '#ffc107' : '#4a4a4a', fontSize: '16px' }}>★</span>
                  ))}
                </div>
              </div>
              <p className="text-gray-300 text-sm mt-2">{comment.text}</p>
            </div>
          ))
        )}
      </div>
      
      <style>{`
        .comment-section {
          max-height: 70vh;
          overflow-y: auto;
        }
        .work-history-item {
          background: rgba(255,255,255,0.08);
          border-radius: 15px;
          padding: 15px;
          margin-bottom: 15px;
          transition: all 0.3s;
          border-left: 4px solid #a855f7;
        }
        .work-history-item:hover {
          background: rgba(255,255,255,0.12);
          transform: translateX(5px);
        }
        .stars {
          display: flex;
          gap: 5px;
        }
        .btn-livre {
          background: linear-gradient(135deg, #22c55e, #15803d);
          border: none;
          padding: 10px 20px;
          border-radius: 25px;
          color: white;
          font-weight: bold;
          cursor: pointer;
          transition: all 0.2s;
        }
        .btn-livre:hover {
          transform: scale(1.02);
          filter: brightness(1.1);
        }
      `}</style>
    </div>
  );
};

export default CommentSection;
